#include <stdio.h>
#include <stdlib.h>
#define MAXB 20
#define SZ (1<<MAXB)
int main(){
    int N,Q; if(scanf("%d %d",&N,&Q)!=2) return 0;
    int *A = (int*)malloc(N*sizeof(int));
    for(int i=0;i<N;i++) scanf("%d",&A[i]);
    static int freq[SZ];
    for(int i=0;i<N;i++) freq[A[i]]++;
    static int dp[SZ];
    for(int mask=0;mask<SZ;mask++) dp[mask]=freq[mask];
    for(int b=0;b<MAXB;b++){
        for(int mask=0;mask<SZ;mask++) if(mask&(1<<b)) dp[mask]+=dp[mask^(1<<b)];
    }
    while(Q--){
        int X,M; scanf("%d %d",&X,&M);
        int ok=1;
        for(int i=0;i<M;i++){
            int idx; scanf("%d",&idx); idx--; // to 0‑based
            if( (A[idx] & ~X) != 0 ) ok=0;
        }
        if(!ok) printf("-1\n");
        else printf("%d\n", dp[X]);
    }
    free(A);
    return 0;
}

