import java.io.*;
import java.util.*;
public class Main {
    static final int MAXB = 20;
    static final int SZ = 1<<MAXB;
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int N = fs.nextInt();
        int Q = fs.nextInt();
        int[] A = new int[N];
        for(int i=0;i<N;i++) A[i]=fs.nextInt();
        int[] freq = new int[SZ];
        for(int v:A) freq[v]++;
        int[] dp = new int[SZ];
        System.arraycopy(freq,0,dp,0,SZ);
        for(int b=0;b<MAXB;b++){
            for(int mask=0;mask<SZ;mask++) if((mask & (1<<b))!=0) dp[mask]+=dp[mask ^ (1<<b)];
        }
        StringBuilder sb = new StringBuilder();
        for(int qi=0; qi<Q; qi++){
            int X = fs.nextInt();
            int M = fs.nextInt();
            boolean ok = true;
            for(int i=0;i<M;i++){
                int idx = fs.nextInt()-1;
                if( (A[idx] & ~X) != 0 ) ok = false;
            }
            if(!ok) sb.append(-1).append('\n');
            else sb.append(dp[X]).append('\n');
        }
        System.out.print(sb.toString());
    }
    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1<<16];
        private int ptr=0, len=0;
        FastScanner(InputStream in){this.in=in;}
        private int readByte() throws IOException{
            if(ptr>=len){ len=in.read(buffer); ptr=0; if(len==-1) return -1; }
            return buffer[ptr++];
        }
        int nextInt() throws IOException{
            int c, sign=1, val=0;
            do{c=readByte();}while(c<=32 && c!=-1);
            if(c=='-'){sign=-1; c=readByte();}
            while(c>32 && c!=-1){ val = val*10 + (c-'0'); c=readByte(); }
            return val*sign;
        }
    }
}

