import sys
MAXB = 20
SZ = 1<<MAXB

def main():
    data = sys.stdin.buffer.read().split()
    it = iter(data)
    N = int(next(it)); Q = int(next(it))
    A = [int(next(it)) for _ in range(N)]
    freq = [0]*SZ
    for v in A:
        freq[v] += 1
    dp = freq[:]
    for b in range(MAXB):
        bit = 1<<b
        for mask in range(SZ):
            if mask & bit:
                dp[mask] += dp[mask ^ bit]
    out_lines = []
    for _ in range(Q):
        X = int(next(it)); M = int(next(it))
        ok = True
        for _ in range(M):
            idx = int(next(it)) - 1
            if A[idx] & (~X):
                ok = False
        out_lines.append(str(-1 if not ok else dp[X]))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

